// Stok seviyesi analizi
const inventory = $input.first().json.items || [$input.first().json];

const today = new Date();
const result = inventory.map(item => {
  const stockLevel = item.quantity || 0;
  const maxStock = item.maxStock || 100;
  const percentage = (stockLevel / maxStock) * 100;

  let status = 'NORMAL';
  let priority = 'LOW';

  if (percentage < 10) {
    status = 'CRITICAL';
    priority = 'CRITICAL';
  } else if (percentage < 20) {
    status = 'URGENT';
    priority = 'HIGH';
  } else if (percentage < 50) {
    status = 'WARNING';
    priority = 'MEDIUM';
  }

  return {
    json: {
      productId: item.productId || item.id,
      productName: item.name || item.productName,
      sku: item.sku,
      currentStock: stockLevel,
      maxStock,
      percentage: Math.round(percentage),
      status,
      priority,
      lastRestock: item.lastRestockDate,
      avgDailySales: item.avgDailySales || 10,
      daysUntilStockout: item.avgDailySales > 0 ? Math.floor(stockLevel / item.avgDailySales) : 999
    }
  };
});

// Kritik ve uyarı olanları filtrele
const criticalItems = result.filter(r => r.json.priority === 'CRITICAL' || r.json.priority === 'HIGH');

return criticalItems.length > 0 ? criticalItems : [{ json: { message: 'No critical stock issues', items: result.map(r => r.json) } }];

