// Otomatik satın alma talebi oluştur
const item = $input.first().json;

// Optimal sipariş miktarı hesapla (basit EOQ)
const annualDemand = item.avgDailySales * 365;
const orderingCost = 500; // TL
const holdingCostRate = 0.25;
const unitCost = item.unitCost || 100;

const eoq = Math.sqrt((2 * annualDemand * orderingCost) / (unitCost * holdingCostRate));
const orderQuantity = Math.min(Math.round(eoq), item.maxStock - item.currentStock);

return [{
  json: {
    productId: item.productId,
    productName: item.productName,
    currentStock: item.currentStock,
    orderQuantity,
    estimatedCost: orderQuantity * unitCost,
    supplier: item.preferredSupplier || 'DEFAULT',
    urgency: item.priority,
    requestedAt: new Date().toISOString(),
    status: 'PENDING_APPROVAL'
  }
}];
